import { defineAgent } from "eve";

export default defineAgent({
  model: "openai/gpt-5.4-mini",
});

import { telegramChannel } from "eve/channels/telegram";

// Credentials come from env: TELEGRAM_BOT_TOKEN and
// TELEGRAM_WEBHOOK_SECRET_TOKEN. See SETUP.md.
export default telegramChannel();

import { defineEvalConfig } from "eve/evals";

export default defineEvalConfig({
  maxConcurrency: 1,
  timeoutMs: 120_000,
});

import { defineEval } from "eve/evals";

export default defineEval({
  description: "Agent boots, accepts a message, and replies in persona.",
  async test(t) {
    await t.send(
      "In one short sentence, who are you and what can you help with?"
    );
    t.succeeded();
  },
});

import { defineEval } from "eve/evals";
import { satisfies } from "eve/evals/expect";

export default defineEval({
  description: "Replies stay short, matching the persona's brevity rule.",
  async test(t) {
    await t.send("Give me three ideas for a Saturday afternoon.");
    t.succeeded();
    t.check(
      t.reply,
      satisfies(
        (reply: string) => reply.split(/\s+/).length < 200,
        "reply is under 200 words"
      )
    ).soft();
  },
});
